import{_ as e,o as r,c as o,ag as i}from"./chunks/framework.B4u4rdkN.js";const m=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),t={name:"faq.md"};function l(n,a,d,h,s,p){return r(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="数据保存在哪里" tabindex="-1">数据保存在哪里？ <a class="header-anchor" href="#数据保存在哪里" aria-label="Permalink to &quot;数据保存在哪里？&quot;">​</a></h2><p>数据存储在 <code>%USERPROFILE%\\AppTimer\\</code> 目录下（通常是 <code>C:\\Users\\你的用户名\\AppTimer\\</code>）。</p><p>按日期子文件夹组织，每天一个 JSON 文件。分类标签和目标设置也保存在该目录。</p><h2 id="如何迁移数据到新电脑" tabindex="-1">如何迁移数据到新电脑？ <a class="header-anchor" href="#如何迁移数据到新电脑" aria-label="Permalink to &quot;如何迁移数据到新电脑？&quot;">​</a></h2><p>直接复制 <code>%USERPROFILE%\\AppTimer\\</code> 整个文件夹到新电脑的同一位置即可，所有历史和设置都会保留。</p><h2 id="深色模式怎么切换" tabindex="-1">深色模式怎么切换？ <a class="header-anchor" href="#深色模式怎么切换" aria-label="Permalink to &quot;深色模式怎么切换？&quot;">​</a></h2><p>两种方式：</p><ol><li><strong>手动切换</strong>：主窗口右上角的深色/浅色开关</li><li><strong>跟随系统</strong>：AppTimer 启动时自动检测 Windows 主题设置（设置 → 个性化 → 颜色）</li></ol><h2 id="为什么有些程序没有被记录" tabindex="-1">为什么有些程序没有被记录？ <a class="header-anchor" href="#为什么有些程序没有被记录" aria-label="Permalink to &quot;为什么有些程序没有被记录？&quot;">​</a></h2><p>AppTimer 只追踪有窗口标题的程序。后台服务、命令行窗口（无标题）、Metro/UWP 应用可能无法正确识别。</p><h2 id="如何设置每日使用目标" tabindex="-1">如何设置每日使用目标？ <a class="header-anchor" href="#如何设置每日使用目标" aria-label="Permalink to &quot;如何设置每日使用目标？&quot;">​</a></h2><ol><li>切换到「分类&amp;目标」标签页</li><li>在右侧「每日目标」区域选择程序</li><li>设定每日使用时长上限（小时/分钟）</li><li>点击保存</li></ol><p>当该程序当日使用时长超过目标时，会弹出提醒。</p><h2 id="休息提醒是什么" tabindex="-1">休息提醒是什么？ <a class="header-anchor" href="#休息提醒是什么" aria-label="Permalink to &quot;休息提醒是什么？&quot;">​</a></h2><p>默认连续使用电脑超过 <strong>45 分钟</strong>，AppTimer 会弹出休息提醒。该阈值可在设置中调整。</p><h2 id="需要联网吗" tabindex="-1">需要联网吗？ <a class="header-anchor" href="#需要联网吗" aria-label="Permalink to &quot;需要联网吗？&quot;">​</a></h2><p>不需要。AppTimer 完全离线运行，所有数据只在本地存储，不会上传任何信息。</p><h2 id="杀毒软件报毒怎么办" tabindex="-1">杀毒软件报毒怎么办？ <a class="header-anchor" href="#杀毒软件报毒怎么办" aria-label="Permalink to &quot;杀毒软件报毒怎么办？&quot;">​</a></h2><p>AppTimer 使用 PyInstaller 打包，部分杀毒软件可能对未签名的 exe 产生误报。可将程序所在文件夹加入杀毒软件白名单。如果仍有顾虑，可以直接用 Python 运行源码 <code>app_timer.py</code>。</p><h2 id="支持哪些-windows-版本" tabindex="-1">支持哪些 Windows 版本？ <a class="header-anchor" href="#支持哪些-windows-版本" aria-label="Permalink to &quot;支持哪些 Windows 版本？&quot;">​</a></h2><p>Windows 10 及以上版本均可使用。</p>',22)])])}const u=e(t,[["render",l]]);export{m as __pageData,u as default};
